// Format the review summary into an email subject + body.
const b = $input.first().json.body ?? $json.body ?? $json;
const count = Number(b.count ?? 0);
const kind = b.kind ?? 'ingest';
const source = b.source ? ` from ${b.source}` : '';
const samples = Array.isArray(b.samples) ? b.samples : [];
const kindLabel = { pod: 'from a subscribed publisher', scrape: 'from a scheduled scrape', subscription: 'from a subscription', ingest: '' }[kind] ?? '';
const subject = `Reckons.AI: ${count} new fact${count === 1 ? '' : 's'} to review${source}`;
const sampleList = samples.length ? '\n\nExamples:\n- ' + samples.slice(0, 5).join('\n- ') : '';
const body = `You have ${count} new fact${count === 1 ? '' : 's'} waiting for review ${kindLabel}.${sampleList}\n\nOpen Reckons.AI → Review to accept, refine, or reject.\n\n(${b.at ?? new Date().toISOString()})`;
return [{ json: { subject, body, count } }];
